int fa[MAXN]; // fa[i] 表示位置 i 及其右侧第一个“激活”的位置

// 标准并查集查找
int find(int x) {
  if (fa[x] == x) return x;
  return fa[x] = find(fa[x]); 
}

void solve() {
  int n = 10;

  // 注意：要初始化到 n + 1，作为越界后的“终点”
  for (int i = 1; i <= n + 1; i++) {
      fa[i] = i;
  }

  // 假设我们要处理区间 [3, 7]
  int L = 3, R = 7;

  // 我们从 find(L) 开始，它会直接带我们找到 L 右侧第一个还没被处理的位置
  for (int i = find(L); i <= R; i = find(i + 1)) {

      // --- 在这里执行你对位置 i 的逻辑 ---
      cout << "处理位置: " << i << endl;
      // ------------------------------

      // “删除”位置 i
      // 将 i 的父亲指向 i + 1 的当前根节点
      // 这样下次 find(i) 或者 find(更小的数) 经过这里时，会直接跳到 i + 1 之后
      fa[i] = find(i + 1);
  }
}
